import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.B45ElpZ1.js";const u=JSON.parse('{"title":"Trader","description":"Active, short-horizon persona built around Streak workflows for Indian equities and options.","frontmatter":{"title":"Trader","description":"Active, short-horizon persona built around Streak workflows for Indian equities and options.","outline":2,"head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/guides/trader"}]]},"headers":[],"relativePath":"guides/trader.md","filePath":"guides/trader.md"}'),i={name:"guides/trader.md"};function s(n,e,l,d,p,c){return a(),r("div",null,[...e[0]||(e[0]=[o(`<h1 id="trader" tabindex="-1">Trader <a class="header-anchor" href="#trader" aria-label="Permalink to &quot;Trader&quot;">​</a></h1><p>Active, short-horizon work on Indian equities and options. Today, Trader is built around <strong><a href="https://streak.tech/" target="_blank" rel="noreferrer">Streak</a></strong> workflows — find, build, backtest, deploy, monitor.</p><h2 id="what-it-s-for" tabindex="-1">What it&#39;s for <a class="header-anchor" href="#what-it-s-for" aria-label="Permalink to &quot;What it&#39;s for&quot;">​</a></h2><ul><li>Equity strategy pipelines (discover → build → backtest → deploy → monitor)</li><li>Options strategies (build → deploy → monitor)</li><li>Read-only options context (OI, PCR, IV, technicals) before building</li><li>Technical setup evaluation and strategy refinement for Indian markets</li><li>Risk-aware trade planning with explicit assumptions and tradeoffs</li></ul><p>Trader is for Streak-first strategy workflows. If you want live chart-native MCP analysis through TradingView, use <a href="/wiki/guides/pro-trader">Pro Trader</a>.</p><h2 id="primary-tools" tabindex="-1">Primary tools <a class="header-anchor" href="#primary-tools" aria-label="Permalink to &quot;Primary tools&quot;">​</a></h2><ul><li>Browser for Streak workflow execution</li><li>Broker MCP tools for account, portfolio, and order context when needed</li><li>News for market-moving developments</li></ul><p>Trader prefers structured workflow tools over open-ended browsing. It uses the browser mainly when a Streak step requires it.</p><h2 id="core-workflows" tabindex="-1">Core workflows <a class="header-anchor" href="#core-workflows" aria-label="Permalink to &quot;Core workflows&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Workflow</th><th>Use it for</th></tr></thead><tbody><tr><td>Equity strategy build</td><td>Full equity pipeline: find, build, backtest, deploy, monitor</td></tr><tr><td>Options strategy build</td><td>Options pipeline: find, build, deploy, monitor</td></tr><tr><td>Options context read</td><td>Read-only OI, PCR, IV, and technical context before building</td></tr></tbody></table><p>Find and evaluate steps are optional. If you already know what you want, Trader can go straight to build, deploy, or monitor.</p><h2 id="typical-prompts" tabindex="-1">Typical prompts <a class="header-anchor" href="#typical-prompts" aria-label="Permalink to &quot;Typical prompts&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Build a NIFTY options strategy for a bullish intraday view</span></span>
<span class="line"><span>/equities       (start the equity strategy pipeline)</span></span>
<span class="line"><span>/options        (start the options strategy pipeline)</span></span>
<span class="line"><span>Read the current options context for BANKNIFTY</span></span>
<span class="line"><span>Monitor my deployed strategies</span></span>
<span class="line"><span>Backtest this equity strategy before deployment</span></span>
<span class="line"><span>Check news that could affect this intraday setup</span></span></code></pre></div><h2 id="broker-behavior" tabindex="-1">Broker behavior <a class="header-anchor" href="#broker-behavior" aria-label="Permalink to &quot;Broker behavior&quot;">​</a></h2><ul><li>If you mention Groww, Trader prefers Groww tools.</li><li>If you mention Zerodha or Kite, Trader prefers Kite tools.</li><li>If the broker matters and you do not specify one, Trader asks a short clarification before taking action.</li></ul><p>Indian cash market hours are 9:15 AM to 3:30 PM IST. Trader should make stale, pre-market, or after-hours context clear when it matters.</p><div class="info custom-block"><p class="custom-block-title">Scope note</p><p>Trader today is Streak-focused. Direct broker-level order placement for arbitrary strategies is evolving — for now, Streak handles the execution layer.</p></div><div class="danger custom-block"><p class="custom-block-title">Safety</p><p>Trader must not fabricate live prices, positions, orders, balances, or broker confirmations. It should not claim a strategy was deployed unless a tool confirms the current state and you explicitly authorized the guarded step.</p></div><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><ul><li><strong>Compare with other personas</strong> → <a href="/wiki/guides/personas">Personas &amp; Modes</a></li><li><strong>Browser setup for Streak automation</strong> → <a href="./../getting-started/browser-setup">Browser Setup</a></li><li><strong>Chart-native trading workflow</strong> → <a href="/wiki/guides/pro-trader">Pro Trader</a></li></ul>`,20)])])}const f=t(i,[["render",s]]);export{u as __pageData,f as default};
